(function($){if(!$.omr){$.omr=new Object();};$.omr.mosaic=function(el,options){var base=this;base.$el=$(el);base.el=el;base.$el.data("omr.mosaic",base);base.init=function(){base.options=$.extend({},$.omr.mosaic.defaultOptions,options);base.load_box();};base.load_box=function(){if(base.options.preload){$(base.options.backdrop,base.el).hide();$(base.options.overlay,base.el).hide();$(window).load(function(){if(base.options.options.animation=='fade'&&$(base.options.overlay,base.el).css('opacity')==0)$(base.options.overlay,base.el).css('filter','alpha(opacity=0)');$(base.options.overlay,base.el).fadeIn(600,function(){$(base.options.backdrop,base.el).fadeIn(600);});base.allow_hover();});}else{$(base.options.backdrop,base.el).show();$(base.options.overlay,base.el).show();base.allow_hover();}};base.allow_hover=function(){switch(base.options.animation){case'fade':$(base.el).hover(function(){$(base.options.overlay,base.el).stop().fadeTo(base.options.speed,base.options.opacity);},function(){$(base.options.overlay,base.el).stop().fadeTo(base.options.speed,0);});break;case'slide':startX=$(base.options.overlay,base.el).css(base.options.anchor_x)!='auto'?$(base.options.overlay,base.el).css(base.options.anchor_x):'0px';startY=$(base.options.overlay,base.el).css(base.options.anchor_y)!='auto'?$(base.options.overlay,base.el).css(base.options.anchor_y):'0px';;var hoverState={};hoverState[base.options.anchor_x]=base.options.hover_x;hoverState[base.options.anchor_y]=base.options.hover_y;var endState={};endState[base.options.anchor_x]=startX;endState[base.options.anchor_y]=startY;$(base.el).hover(function(){$(this).find(".img-colour.not-hovered").first().removeClass("not-hovered");$(base.options.overlay,base.el).stop().animate(hoverState,base.options.speed,function(){$(".not-hovered").stop().animate({"opacity":"0"},"slow");});},function(){$(base.options.overlay,base.el).stop().animate(endState,base.options.speed);$(".not-hovered").fadeTo('slow',1,function(){});$(".img-colour").addClass("not-hovered");});break;};};base.init();};$.omr.mosaic.defaultOptions={animation:'fade',speed:600,opacity:1,preload:0,anchor_x:'left',anchor_y:'bottom',hover_x:'0px',hover_y:'0px',overlay:'.mosaic-overlay',backdrop:'.mosaic-backdrop',imgColour:'.img-colour'};$.fn.mosaic=function(options){return this.each(function(){(new $.omr.mosaic(this,options));});};})(jQuery);jQuery(function($){$('.circle').mosaic({opacity:0.8});$('.fade').mosaic();$('.bar').mosaic({animation:'slide'});$('.bar2').mosaic({animation:'slide'});$('.bar3').mosaic({animation:'slide',anchor_y:'top'});$('.cover').mosaic({animation:'slide',hover_x:'400px'});$('.cover2').mosaic({animation:'slide',anchor_y:'top',hover_y:'80px'});$('.cover3').mosaic({animation:'slide',hover_x:'400px',hover_y:'300px'});});